(12, 'Annual Hackathon 2026 Registration Open', 'Get ready! The Learnlike Annual Hackathon is scheduled for June 28-29. Form teams of 3-5 and submit your project ideas to HR by this Friday. Top three teams win cash prizes!', 'event', 87, 'all', 1, NULL, NULL, 1, '2026-06-15 11:39:22', '2026-06-15 11:39:22'),
(13, 'Updated WFH & Remote Work Policy Guidelines', 'The management has updated the guidelines for Work From Home approvals. Please review the updated policy document in the WFH Policy section. Contact your reporting managers for details.', 'policy', 87, 'all', 0, NULL, NULL, 1, '2026-06-15 11:39:22', '2026-06-15 11:39:22'),
(14, 'Office Townhall & Birthday Celebration', 'Join us in the cafeteria today at 4:30 PM for our monthly townhall update followed by cake cutting to celebrate all team birthdays in June!', 'birthday', 87, 'all', 0, NULL, NULL, 1, '2026-06-15 11:39:22', '2026-06-15 11:39:22'),
(16, 'New WFH Policy Update', 'Please review the updated Work From Home policy available in the HR portal. The new guidelines will be effective starting next month.', 'announcement', 87, 'all', 0, NULL, NULL, 1, '2026-07-10 07:40:04', '2026-07-10 07:40:04'),
(17, 'Q3 Company Townhall', 'Join us next Friday at 2:00 PM for the Q3 Company Townhall. We will be discussing our upcoming goals and recent achievements.', 'event', 87, 'all', 0, NULL, NULL, 1, '2026-07-10 07:40:04', '2026-07-10 07:40:04'),
(18, 'System Maintenance Scheduled', 'The AMS portal will be undergoing scheduled maintenance this Saturday from 2:00 AM to 4:00 AM. During this time, the system will be unavailable.', 'announcement', 87, 'all', 0, NULL, NULL, 1, '2026-07-10 07:49:30', '2026-07-10 07:49:30'),
(19, 'Welcome New Hires!', 'Please join us in welcoming the new batch of engineers who joined the team this week. Make sure to say hi when you see them around the office!', 'announcement', 87, 'all', 0, NULL, NULL, 1, '2026-07-10 07:49:30', '2026-07-10 07:49:30'),
(20, 'Health & Wellness Session', 'A reminder that the mandatory Health & Wellness session will be conducted next Wednesday. A calendar invite has been sent with the meeting link.', 'event', 87, 'all', 0, NULL, NULL, 1, '2026-07-10 07:49:30', '2026-07-10 07:49:30');

