--
-- Table structure for table `payrolls`
--

CREATE TABLE `payrolls` (
  `id` int NOT NULL,
  `user_id` int NOT NULL,
  `month` int NOT NULL,
  `year` int NOT NULL,
  `base_salary` decimal(10,2) NOT NULL,
  `allowance_hra` decimal(10,2) DEFAULT '0.00',
  `allowance_transport` decimal(10,2) DEFAULT '0.00',
  `allowance_other` decimal(10,2) DEFAULT '0.00',
  `deduction_pf` decimal(10,2) DEFAULT '0.00',
  `deduction_tax` decimal(10,2) DEFAULT '0.00',
  `deduction_lop` decimal(10,2) DEFAULT '0.00',
  `net_salary` decimal(10,2) NOT NULL,
  `status` enum('Draft','Paid','Cancelled') DEFAULT 'Draft',
  `paid_at` datetime DEFAULT NULL,
  `remarks` text,
  `created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;

